data.query:
query User($userId: String) {
    user(id: $userId) {
        user_id
        name
        email
        num_transcripts
        recent_transcript
        recent_meeting
        minutes_consumed
        is_admin
        integrations
        is_calendar_in_sync
        user_groups {
            id
            name
            handle
            members {
                user_id
                first_name
                last_name
                email
            }
        }
    }
}
